class Solution:
    def romanToInt(self, s: str) -> int:
        m = {'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000}
        res = 0
        for i, c in enumerate(s):
            if i+1 < len(s) and m[c] < m[s[i+1]]: res -= m[c]
            else: res += m[c]
        return res

